#include <bits/stdc++.h>
using namespace std;
const int maxn=1e2+5;
int n,m,rr,ans;
vector<int> a(maxn);
bool cmp(int a,int b){
	return a>b;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=0; i<n*m; i++) {
		cin>>a[i];
	}
	rr=a[0];
	sort(a.begin(),a.end(),cmp);
	vector<vector<int>> aa(n,vector<int> (m));
	for(int j=0; j<m; j++) {
		if(j%2==0) {
			for(int i=0; i<n; i++) {
				aa[i][j]=a[ans++];
			}
		} else {
			for(int i=n-1; i>=0; i--) {
				aa[i][j]=a[ans++];
			}
		}
	}
	for(int i=0; i<n; i++) {
		for(int j=0; j<m; j++) {
			if(aa[i][j]==rr) {
				cout<<j+1<<" "<<i+1;
				return 0;
			}
		}
	}
	return 0;
}
